class Vector2{constructor({x:x=0,y:y=0}){this.x=x,this.y=y}static formOffsets(info){return new Vector2({x:info.offsetX,y:info.offsetY})}static zero(){return new Vector2({})}static load(data){return new Vector2(data)}static mid(vectors){const minX=Math.min(...vectors.map((p=>p.x))),maxX=Math.max(...vectors.map((p=>p.x))),minY=Math.min(...vectors.map((p=>p.y))),maxY=Math.max(...vectors.map((p=>p.y)));return new Vector2({x:minX+(maxX-minX)/2,y:minY+(maxY-minY)/2})}static add(v1,v2){return v1.add(v2)}static subtract(v1,v2){return v1.subtract(v2)}static magnitude(v){return v.magnitude()}static scale(v,scaler){return v.scale(scaler)}static min(v1,v2){v1.min(v2)}static max(v1,v2){v1.max(v2)}static dot(v1,v2){return v1.dot(v2)}static topLeft(vectors){let topLeft=vectors[0];for(const vector of vectors)topLeft=topLeft.min(vector);return topLeft}static bottomRight(vectors){let bottomRight=vectors[0];for(const vector of vectors)bottomRight=bottomRight.max(vector);return bottomRight}static getSignAngle(v1,v2){return Math.atan2(v1.y,v1.x)-Math.atan2(v2.y,v2.x)}static rotateAroundCenter(v,center,angle){let{x:x,y:y}=Vector2.subtract(v,center),rotated=new Vector2({x:x*Math.cos(angle)-y*Math.sin(angle),y:y*Math.sin(angle)-x*Math.cos(angle)});return Vector2.subtract(rotated,center)}static distance(v1,v2){return v1.subtract(v2).magnitude()}static toXY({dir:dir,mag:mag}){return new Vector2({x:mag*Math.cos(dir),y:mag*Math.sin(dir)})}add(v){return new Vector2({x:this.x+v.x,y:this.y+v.y})}subtract(v){return new Vector2({x:this.x-v.x,y:this.y-v.y})}magnitude(){return Math.sqrt(this.x**2+this.y**2)}scale(scaler){return new Vector2({x:this.x*scaler,y:this.y*scaler})}min(v){return new Vector2({x:Math.min(this.x,v.x),y:Math.min(this.y,v.y)})}max(v){return new Vector2({x:Math.max(this.x,v.x),y:Math.max(this.y,v.y)})}dot(v){return this.x*v.x+this.y*v.y}normalize(){const mag=this.magnitude();return 0===mag?Vector2.zero():this.scale(1/mag)}direction(){return Math.atan2(this.y,this.x)}toPolar(){return{dir:this.direction(),mag:this.magnitude()}}toXY({dir:dir,mag:mag}){return new Vector2({x:mag*Math.cos(dir),y:mag*Math.sin(dir)})}clone(){return new Vector2(this)}}export{Vector2};